// src/components/admin/StaffDashboard.jsx
import React, { useEffect, useState } from "react";
import axios from "axios";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

export default function StaffDashboard() {
  const [activeTab, setActiveTab] = useState("dashboard");
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({
    checked_in: 0,
    available: 0,
    pending_requests: 0,
    rooms_to_clean: 0,
    today_checkins: 0,
    today_checkouts: 0,
  });
  const [guests, setGuests] = useState([]);
  const [rooms, setRooms] = useState([]);
  const [housekeeping, setHousekeeping] = useState([]);
  const [todaysGuests, setTodaysGuests] = useState([]);

  useEffect(() => {
    loadData();
  }, []);

  async function loadData() {
    setLoading(true);
    try {
      const [resRes, roomsRes, checkinsRes] = await Promise.allSettled([
        axios.get(`${API_BASE}/api/reservations/`),
        axios.get(`${API_BASE}/api/rooms/`),
        axios.get(`${API_BASE}/api/admin/confirmed-guests/`),
      ]);

      const reservations = resRes.status === "fulfilled" ? resRes.value.data : [];
      const roomsData = roomsRes.status === "fulfilled" ? roomsRes.value.data : [];
      const checkins = checkinsRes.status === "fulfilled" ? checkinsRes.value.data : [];

      const today = new Date().toISOString().slice(0, 10);
      
      // Stats
      const checkedIn = checkins.filter((c) => (c.status || "").toLowerCase() === "checked-in" || c.status === "Confirmed").length;
      const pending = reservations.filter((r) => (r.status || "").toLowerCase() === "pending").length;
      const available = roomsData.filter((r) => (r.status || "").toLowerCase() === "available").length;
      const toClean = roomsData.filter((r) => (r.status || "").toLowerCase() === "needs_cleaning").length;

      // Today's check-ins and check-outs
      const todayCheckins = reservations.filter((r) => {
        const checkIn = (r.check_in || "").slice(0, 10);
        return checkIn === today && (r.status || "").toLowerCase() === "confirmed";
      });
      
      const todayCheckouts = reservations.filter((r) => {
        const checkOut = (r.check_out || "").slice(0, 10);
        return checkOut === today && (r.status || "").toLowerCase() === "confirmed";
      });

      setStats({
        checked_in: checkedIn,
        available: available,
        pending_requests: pending,
        rooms_to_clean: toClean,
        today_checkins: todayCheckins.length,
        today_checkouts: todayCheckouts.length,
      });

      // Guest list (currently checked-in)
      setGuests(checkins.filter((c) => (c.status || "").toLowerCase() === "checked-in" || c.status === "Confirmed"));

      // Today's guests (check-in or check-out today)
      const todayGuestsData = [
        ...todayCheckins.map(r => ({
          ...r,
          guestType: 'check-in',
          guestName: r.guest_name || r.name || 'Guest',
          room: r.room_type || r.rooms || r.room_name || '-',
          checkInDate: r.check_in,
          checkOutDate: r.check_out,
        })),
        ...todayCheckouts.map(r => ({
          ...r,
          guestType: 'check-out',
          guestName: r.guest_name || r.name || 'Guest',
          room: r.room_type || r.rooms || r.room_name || '-',
          checkInDate: r.check_in,
          checkOutDate: r.check_out,
        }))
      ];
      setTodaysGuests(todayGuestsData);

      // Room status
      setRooms(roomsData);

      // Housekeeping tasks
      setHousekeeping(
        roomsData
          .filter((r) => (r.status || "").toLowerCase() === "needs_cleaning")
          .map((r) => ({ ...r, task: "Clean Room", priority: "High" }))
      );

    } catch (err) {
      console.error("Failed to load data:", err);
    } finally {
      setLoading(false);
    }
  }

  async function handleCheckOut(guestId) {
    try {
      await axios.patch(`${API_BASE}/api/guest_checkins/${guestId}/`, { status: "checked-out" });
      loadData();
    } catch (err) {
      console.error("Check-out failed:", err);
    }
  }

  async function handleMarkClean(roomId) {
    try {
      await axios.patch(`${API_BASE}/api/rooms/${roomId}/`, { status: "available" });
      loadData();
    } catch (err) {
      console.error("Mark clean failed:", err);
    }
  }

  function handleLogout() {
    localStorage.removeItem('access_token');
    localStorage.removeItem('refresh_token');
    localStorage.removeItem('username');
    localStorage.removeItem('role');
    localStorage.removeItem('email');
    window.location.href = "/staff-login";
  }

  // Helper for rendering room images
  function renderRoomImage(room) {
    const imgs = room.images ?? room.room_images ?? [];
    if (Array.isArray(imgs) && imgs.length > 0) {
      let src = imgs[0]?.url ?? imgs[0]?.image ?? imgs[0] ?? '';
      if (!src && imgs[0]?.image) {
        src = imgs[0].image.url ?? imgs[0].image.path ?? '';
      }
      if (src) {
        return src.startsWith("http") ? src : `${API_BASE}${src}`;
      }
    }
    return null;
  }

  return (
    <div style={{ display: "flex", minHeight: "100vh", background: "#181818", color: "#f1f1f1" }}>
      <style>{`
        :root{--bg-sidebar:#202020;--card:#2a2a2a;--accent:#c89d5c;--muted:#aaa}
        .sidebar-container{width:220px;min-height:100vh;background:var(--bg-sidebar);padding:20px;display:flex;flex-direction:column;position:fixed;top:0;left:0;height:100vh}
        .sidebar-title{color:var(--accent);font-size:20px;margin-bottom:24px;font-weight:600}
        .sidebar-nav{display:flex;flex-direction:column;flex:1}
        .sidebar-link{color:var(--muted);text-decoration:none;padding:10px 12px;border-radius:6px;margin-bottom:4px;transition:all 0.2s ease;cursor:pointer}
        .sidebar-link:hover{color:var(--accent);background:rgba(200,157,92,0.1)}
        .sidebar-link.active{color:var(--accent);background:rgba(200,157,92,0.15)}
        .sidebar-btn{color:var(--muted);padding:10px 12px;border-radius:6px;margin-bottom:4px;transition:all 0.2s ease;cursor:pointer;background:none;border:none;text-align:left;width:100%;font-size:14px}
        .sidebar-btn:hover{color:var(--accent);background:rgba(200,157,92,0.1)}
        .sidebar-btn.active{color:var(--accent);background:rgba(200,157,92,0.15)}
        .sidebar-logout{margin-top:auto;padding-top:20px;border-top:1px solid #333}
        .sidebar-logout .btn-logout:hover{background:rgba(200,157,92,0.2)}
        .main-content{flex:1;margin-left:220px;padding:28px;min-height:100vh}
        .topbar{display:flex;justify-content:space-between;align-items:center;margin-bottom:20px}
        .topbar h1{color:var(--accent)}
        .cards{display:grid;grid-template-columns:repeat(4,1fr);gap:18px;margin-bottom:20px}
        .card{background:var(--card);padding:16px;border-radius:8px;text-align:center}
        .card h4{color:var(--muted);margin-bottom:8px}
        .card p{font-size:20px;color:var(--accent);font-weight:700}
        .section{display:none}
        .section.active{display:block}
        .box{background:var(--card);padding:16px;border-radius:8px;margin-bottom:16px}
        .box h3{color:var(--accent);margin-bottom:12px}
        table{width:100%;border-collapse:collapse}
        th,td{padding:10px;text-align:left;border-bottom:1px solid #444}
        th{color:var(--accent)}
        .btn-checkout{background:#c89d5c;color:#111;padding:6px 12px;border-radius:4px;border:none;cursor:pointer}
        .btn-clean{background:#4ade80;color:#111;padding:6px 12px;border-radius:4px;border:none;cursor:pointer}
        .btn-logout{background:#ef4444;color:#fff;padding:6px 12px;border-radius:4px;border:none;cursor:pointer;width:100%;text-align:center}
        .order-status{padding:4px 10px;border-radius:12px;font-size:11px;font-weight:600}
        .status-pending{background:#fbbf24;color:#000}
        .status-preparing{background:#60a5fa;color:#fff}
        .status-ready{background:#34d399;color:#000}
        .guest-type{_padding:4px 8px;border-radius:4px;font-size:11px;font-weight:600}
        .type-checkin{background:#4ade80;color:#111}
        .type-checkout{background:#f87171;color:#fff}
        
        /* Accommodations Grid */
        .accommodations-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:24px}
        .room-card{background:var(--card);border-radius:12px;overflow:hidden;transition:transform 0.2s}
        .room-card:hover{transform:translateY(-4px)}
        .room-image{width:100%;height:200px;object-fit:cover;background:#333}
        .room-info{padding:16px}
        .room-name{color:var(--accent);font-size:18px;font-weight:600;margin-bottom:8px}
        .room-desc{color:var(--muted);font-size:14px;margin-bottom:12px;line-height:1.5}
        .room-price{color:#fff;font-size:20px;font-weight:700}
        .room-price span{font-size:14px;color:var(--muted);font-weight:400}
        .room-capacity{color:var(--muted);font-size:13px;margin-top:8px}
        .room-amenities{display:flex;gap:8px;flex-wrap:wrap;margin-top:12px}
        .amenity{background:rgba(200,157,92,0.2);color:var(--accent);padding:4px 10px;border-radius:20px;font-size:12px}
        
        @media(max-width:900px){
          .cards{grid-template-columns:repeat(2,1fr)}
          .sidebar-container{display:none}
          .main-content{margin-left:0}
        }
      `}</style>

      <aside className="sidebar-container">
        <h2 className="sidebar-title">Staff Portal</h2>
        <nav className="sidebar-nav">
          <button className={`sidebar-btn ${activeTab === "dashboard" ? "active" : ""}`} onClick={() => setActiveTab("dashboard")}>Dashboard</button>
          <button className={`sidebar-btn ${activeTab === "guests" ? "active" : ""}`} onClick={() => setActiveTab("guests")}>Guest Management</button>
          <button className={`sidebar-btn ${activeTab === "rooms" ? "active" : ""}`} onClick={() => setActiveTab("rooms")}>Room Status</button>
          <button className={`sidebar-btn ${activeTab === "accommodations" ? "active" : ""}`} onClick={() => setActiveTab("accommodations")}>Accommodations</button>
          <button className={`sidebar-btn ${activeTab === "housekeeping" ? "active" : ""}`} onClick={() => setActiveTab("housekeeping")}>Housekeeping</button>
        </nav>
        <div className="sidebar-logout">
          <button className="btn-logout" onClick={handleLogout}>Logout</button>
        </div>
      </aside>

      <main className="main-content">
        <div className="topbar">
          <h1>{activeTab === "dashboard" ? "Dashboard" : activeTab === "accommodations" ? "Accommodations" : activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}</h1>
        </div>

        {/* Dashboard Stats */}
        <div className={`section ${activeTab === "dashboard" ? "active" : ""}`}>
          <div className="cards">
            <div className="card">
              <h4>Today's Check-ins</h4>
              <p>{loading ? "..." : stats.today_checkins}</p>
            </div>
            <div className="card">
              <h4>Today's Check-outs</h4>
              <p>{loading ? "..." : stats.today_checkouts}</p>
            </div>
            <div className="card">
              <h4>Currently Checked In</h4>
              <p>{loading ? "..." : stats.checked_in}</p>
            </div>
            <div className="card">
              <h4>Available Rooms</h4>
              <p>{loading ? "..." : stats.available}</p>
            </div>
          </div>

          {/* Today's Guests Section */}
          <div className="box">
            <h3>Today's Guests</h3>
            {loading ? (
              <p>Loading...</p>
            ) : todaysGuests.length === 0 ? (
              <p style={{ color: "var(--muted)" }}>No guests expected today.</p>
            ) : (
              <table>
                <thead>
                  <tr>
                    <th>Guest Name</th>
                    <th>Room</th>
                    <th>Type</th>
                    <th>Check-In</th>
                    <th>Check-Out</th>
                  </tr>
                </thead>
                <tbody>
                  {todaysGuests.map((g, idx) => (
                    <tr key={idx}>
                      <td>{g.guestName}</td>
                      <td>{g.room}</td>
                      <td>
                        <span className={`guest-type ${g.guestType === 'check-in' ? 'type-checkin' : 'type-checkout'}`}>
                          {g.guestType === 'check-in' ? 'Check-In' : 'Check-Out'}
                        </span>
                      </td>
                      <td>{g.checkInDate || '-'}</td>
                      <td>{g.checkOutDate || '-'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>

          <div className="box">
            <h3>Quick Actions</h3>
            <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
              <button onClick={() => setActiveTab("guests")} style={{ background: "var(--accent)", color: "#111", padding: "10px 20px", borderRadius: 6, border: "none", cursor: "pointer" }}>View All Guests</button>
              <button onClick={() => setActiveTab("housekeeping")} style={{ background: "#4ade80", color: "#111", padding: "10px 20px", borderRadius: 6, border: "none", cursor: "pointer" }}>Housekeeping Tasks</button>
              <button onClick={() => setActiveTab("accommodations")} style={{ background: "#60a5fa", color: "#111", padding: "10px 20px", borderRadius: 6, border: "none", cursor: "pointer" }}>View Accommodations</button>
            </div>
          </div>
        </div>

        {/* Guest Management */}
        <div className={`section ${activeTab === "guests" ? "active" : ""}`}>
          <div className="box">
            <h3>Currently Checked-In Guests</h3>
            {loading ? (
              <p>Loading...</p>
            ) : guests.length === 0 ? (
              <p>No guests currently checked in.</p>
            ) : (
              <table>
                <thead>
                  <tr>
                    <th>Guest Name</th>
                    <th>Room</th>
                    <th>Check-In</th>
                    <th>Check-Out</th>
                    <th>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {guests.map((g) => (
                    <tr key={g.id}>
                      <td>{g.guest_name || g.name || "Guest"}</td>
                      <td>{g.room_type || g.room_name || "-"}</td>
                      <td>{g.check_in || g.checkin || "-"}</td>
                      <td>{g.check_out || g.checkout || "-"}</td>
                      <td>
                        <button className="btn-checkout" onClick={() => handleCheckOut(g.id)}>Check Out</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </div>

        {/* Room Status */}
        <div className={`section ${activeTab === "rooms" ? "active" : ""}`}>
          <div className="box">
            <h3>All Rooms Status</h3>
            {loading ? (
              <p>Loading...</p>
            ) : rooms.length === 0 ? (
              <p>No rooms found.</p>
            ) : (
              <table>
                <thead>
                  <tr>
                    <th>Room Name</th>
                    <th>Type</th>
                    <th>Status</th>
                    <th>Price</th>
                  </tr>
                </thead>
                <tbody>
                  {rooms.map((r) => (
                    <tr key={r.id}>
                      <td>{r.room_name || r.name}</td>
                      <td>{r.room_type || "-"}</td>
                      <td>
                        <span style={{
                          padding: "4px 8px",
                          borderRadius: 4,
                          background: r.status === "available" ? "#4ade80" : r.status === "occupied" ? "#c89d5c" : "#f87171",
                          color: "#111"
                        }}>
                          {r.status}
                        </span>
                      </td>
                      <td>₹{r.price || 0}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </div>

        {/* Accommodations */}
        <div className={`section ${activeTab === "accommodations" ? "active" : ""}`}>
          <div className="box">
            <h3>Room Details</h3>
            <p style={{ color: "var(--muted)", marginBottom: "20px" }}>View all available accommodations with details</p>
          </div>
          
          {loading ? (
            <p>Loading...</p>
          ) : rooms.length === 0 ? (
            <p>No rooms available.</p>
          ) : (
            <div className="accommodations-grid">
              {rooms.map((room) => {
                const imageUrl = renderRoomImage(room);
                return (
                  <div className="room-card" key={room.id}>
                    {imageUrl ? (
                      <img src={imageUrl} alt={room.room_name || room.name} className="room-image" />
                    ) : (
                      <div className="room-image" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#666' }}>
                        No Image
                      </div>
                    )}
                    <div className="room-info">
                      <div className="room-name">{room.room_name || room.name || 'Room'}</div>
                      <div className="room-desc">{room.description || 'No description available.'}</div>
                      <div className="room-price">
                        ₹{Number(room.price || 0).toLocaleString(undefined, { maximumFractionDigits: 0 })}
                        <span>/night</span>
                      </div>
                      <div className="room-capacity">
                        Capacity: {room.capacity || 2} guests
                      </div>
                      <div className="room-amenities">
                        {room.is_available !== false && (
                          <span className="amenity">Available</span>
                        )}
                        {room.capacity && <span className="amenity">{room.capacity} Guests</span>}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Housekeeping */}
        <div className={`section ${activeTab === "housekeeping" ? "active" : ""}`}>
          <div className="box">
            <h3>Pending Housekeeping Tasks</h3>
            {loading ? (
              <p>Loading...</p>
            ) : housekeeping.length === 0 ? (
              <p>All rooms are clean!</p>
            ) : (
              <table>
                <thead>
                  <tr>
                    <th>Room</th>
                    <th>Task</th>
                    <th>Priority</th>
                    <th>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {housekeeping.map((h) => (
                    <tr key={h.id}>
                      <td>{h.room_name || h.name}</td>
                      <td>{h.task}</td>
                      <td>
                        <span style={{ color: h.priority === "High" ? "#ef4444" : "#aaa" }}>
                          {h.priority}
                        </span>
                      </td>
                      <td>
                        <button className="btn-clean" onClick={() => handleMarkClean(h.id)}>Mark Clean</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </div>

      </main>
    </div>
  );
}
